INSERT INTO regimen_urbanistico (TIPO_DISTRITO,DISTRITO,DESCRIPCION,ESPECIFICIDAD,MODALIDAD,FRENTE_MIN,SUP_MINIMA,FOT_PRIVADO,FOT_PUB_CREADO,FOT_PUB_TDP,FOT_PUB_EMI_REC,FOS,R_JARDIN,R_FONDO,R_BASAMENTO,R_FRENTE,R_LATERAL,H_FOT_PRIV,H_FOT_PUB,H_FOT_BASAMENTO,H_MAX,OBSERVACIONES) VALUES ('URBANO','RM1','Distrito que, en razón de presentar el mayor nivel de consolidación, buena accesibilidad, diversidad e intensidad de usos y servicios para el desarrollo de la vida cotidiana, se destina principalmente a absorber mayor densificación. Admite usos compatibles de pequeña y mediana escala con afluencia macro.',NULL,NULL,10.0,400.0,4.9,2.8,'-','R',0.7,'-','1/3 H (*6)','(*4)',NULL,NULL,21.0,33.0,NULL,NULL,'(*1) Altura de edificación para edificios entre medianeras sin aplicación del régimen de perímetro libre.              
(*2) Para inmuebles y/o proyectos colindantes a equipamientos de aviación civil, la altura de edificación, de plano límite y del volumen superior deberá ajustarse a los requerimientos de la Administración Nacional de Aviación Civil - ANAC.             
(*3) En el caso de pasajes ubicados en los distritos RM1, RM2, RM3, CC1, CC3, CC4,CC5, CC6 la altura sobre Línea Municipal no podrá ser mayor al rebatimiento del ancho del pasaje. Por sobre este rebatimiento podrá llegarse a la altura establecida para el distrito, retirando la línea de fachada o el borde exterior de los balcones a 4,00m desde la línea municipal.             
(*4) La emisión o recepcion de FOT Público se pondrá en vigencia con planes o programas de incentivo.             
(*5) El régimen de perímetro libre es aplicable en distritos del Área Urbana, excepto en los distritos de AC, CC2, RM4, RM5.             
