INSERT INTO regimen_urbanistico (TIPO_DISTRITO,DISTRITO,DESCRIPCION,ESPECIFICIDAD,MODALIDAD,FRENTE_MIN,SUP_MINIMA,FOT_PRIVADO,FOT_PUB_CREADO,FOT_PUB_TDP,FOT_PUB_EMI_REC,FOS,R_JARDIN,R_FONDO,R_BASAMENTO,R_FRENTE,R_LATERAL,H_FOT_PRIV,H_FOT_PUB,H_FOT_BASAMENTO,H_MAX,OBSERVACIONES) VALUES ('URBANO','PA','Espacios abiertos activos con infraestructura y equipamiento urbano concebido para su utilización plena en uso público intensivo orientado principalmente a usos deportivos, recreativos o turísticos. Se incluyen en esta categoría: Parque Bicentenario, Parque Campo la Cruz, Parque 20 de Febrero, Parque San Martín, Parque Ribera del Río Arias - Arenales, Parque de la Familia, Parque Sur, Parque Ribera de San Luis, Parque Ribera Río Vaqueros.','SEGÚN ORDENANZA 15675 Y REGLAMENTACION PARA CONCESION DE ESPACIOS PUBLICOS',NULL,'10000(*1)','70(*1)','0.2(*1)',NULL,NULL,NULL,'0.1(*1)(*2)',NULL,'10(*1)',NULL,NULL,'10(*1)',NULL,NULL,NULL,'8(*1)','(*1) Indicadores para Parque Activo de la Ribera del Río Vaqueros.             
INSERT INTO regimen_urbanistico (TIPO_DISTRITO,DISTRITO,DESCRIPCION,ESPECIFICIDAD,MODALIDAD,FRENTE_MIN,SUP_MINIMA,FOT_PRIVADO,FOT_PUB_CREADO,FOT_PUB_TDP,FOT_PUB_EMI_REC,FOS,R_JARDIN,R_FONDO,R_BASAMENTO,R_FRENTE,R_LATERAL,H_FOT_PRIV,H_FOT_PUB,H_FOT_BASAMENTO,H_MAX,OBSERVACIONES) VALUES ('URBANO','PP','Espacios abiertos pasivos en los que, por determinadas características (generalmente condicionantes para la seguridad, la salud o el ambiente), la utilización pública es prohibida o restringida, siendo su finalidad la de contribuir a la regeneración de ecosistemas, proporcionar pulmones verdes, permitir la accesibilidad a fuentes de aprovisionamiento de agua o instalaciones urbanas primarias, generar áreas de drenaje natural y buffers para acuíferos, aportar a la calidad paisajística de la ciudad, y otros. Se trata en general de zonas destinadas a la forestación, y parquización, sin perjuicio de que, a través de adecuados procesos de saneamiento o recuperación ambiental, pueden ser convertidos a futuro en espacios abiertos activos. Se incluyen en esta categoría: Antiguas Lagunas Cloacales de la Zona Norte,  Fuelle Sur Parque Industrial (Ex Basural de La Pedrera), Franjas de Seguridad de las Líneas de Alta Tensión, Franjas de Seguridad del Ferrocarril.
