INSERT INTO regimen_urbanistico (TIPO_DISTRITO,DISTRITO,DESCRIPCION,ESPECIFICIDAD,MODALIDAD,FRENTE_MIN,SUP_MINIMA,FOT_PRIVADO,FOT_PUB_CREADO,FOT_PUB_TDP,FOT_PUB_EMI_REC,FOS,R_JARDIN,R_FONDO,R_BASAMENTO,R_FRENTE,R_LATERAL,H_FOT_PRIV,H_FOT_PUB,H_FOT_BASAMENTO,H_MAX,OBSERVACIONES) VALUES ('SUBURBANO','FU','Distrito orientado a su utilización prioritaria como espacio abierto garantizando el acceso, protección, aprovechamiento sustentable y disfrute de sus recursos naturales y paisajísticos por parte de la comunidad, destinado a articular los espacios verdes con los distritos urbanizables, preservando asimismo las escorrentías y las áreas con índice fenológico boscoso y bosque denso. Admite edificaciones puntuales de soporte a las actividades permitidas, siempre que verifique aptitud ambiental.','FICHA DE DISTRITO ANEXO 4.4',NULL,NULL,NULL,NULL,NULL,NULL,'E',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'(*1) Indicadores y actividades permitidas sujetas a la presentación de un Plan de Manejo Especifico del área.
(*2) Actividad complementaria a la función principal. A evaluarse en el marco de un proyecto integral.');
